# ========================================
# 도메인 지식
# ========================================

ax:AIEthics a ax:DomainKnowledge ;
    rdfs:label "AI 윤리"@ko, "AI Ethics"@en ;
    dcterms:description "공정성, 투명성, 책임성, 편향 완화"@ko ;
    ax:partOfCluster ax:AIGovernanceCluster ;
    ax:marketDemand "88.6"^^xsd:decimal ;
    ax:emergingTrend true ;
    ax:learningTime "P4M"^^xsd:duration ;
    ax:businessImpact "Critical" ;
    ax:certificationAvailable true ;
    ax:appliesTo ax:AIEthicsOfficer, ax:AIStrategist .

ax:AIRegulation a ax:DomainKnowledge ;
    rdfs:label "AI 규제"@ko, "AI Regulation"@en ;
    dcterms:description "EU AI Act, GDPR, 개인정보보호법"@ko ;
    ax:partOfCluster ax:AIGovernanceCluster ;
    ax:marketDemand "84.3"^^xsd:decimal ;
    ax:emergingTrend true ;
    ax:learningTime "P4M"^^xsd:duration ;
    ax:businessImpact "Critical" ;
    ax:appliesTo ax:AIEthicsOfficer, ax:AIStrategist .

ax:ExplainableAI a ax:DomainKnowledge ;
    rdfs:label "설명 가능 AI"@ko, "Explainable AI"@en ;
