    ax:marketDemand "82.9"^^xsd:decimal ;
    ax:emergingTrend true ;
    ax:learningTime "P3M"^^xsd:duration ;
    ax:businessImpact "High" ;
    ax:salaryPremium "29.0"^^xsd:decimal ;
    ax:appliesTo ax:MLEngineer, ax:DataScientist, ax:AIEthicsOfficer .

ax:FairnessBiasMitigation a ax:DomainKnowledge ;
    rdfs:label "공정성 및 편향 완화"@ko, "Fairness & Bias Mitigation"@en ;
    dcterms:description "편향 측정, 완화 기법, 공정성 지표"@ko ;
    ax:partOfCluster ax:AIGovernanceCluster ;
    ax:marketDemand "79.7"^^xsd:decimal ;
    ax:emergingTrend true ;
    ax:learningTime "P3M"^^xsd:duration ;
    ax:businessImpact "Critical" ;
    ax:salaryPremium "31.0"^^xsd:decimal ;
    ax:appliesTo ax:MLEngineer, ax:DataScientist, ax:AIEthicsOfficer .

ax:ModelGovernance a ax:DomainKnowledge ;
    rdfs:label "모델 거버넌스"@ko, "Model Governance"@en ;
    dcterms:description "모델 승인, 감사, 폐기 정책"@ko ;
    ax:partOfCluster ax:AIGovernanceCluster ;
    ax:marketDemand "76.4"^^xsd:decimal ;
    ax:emergingTrend true ;
    ax:learningTime "P3M"^^xsd:duration ;
    ax:businessImpact "High" ;
    ax:appliesTo ax:MLOpsEngineer, ax:AIEthicsOfficer .

ax:DataPrivacy a ax:DomainKnowledge ;
    rdfs:label "데이터 프라이버시"@ko, "Data Privacy"@en ;
    dcterms:description "차등 프라이버시, 연합 학습, 암호화"@ko ;
    ax:partOfCluster ax:AIGovernanceCluster ;
    ax:marketDemand "85.1"^^xsd:decimal ;
    ax:emergingTrend true ;
    ax:learningTime "P4M"^^xsd:duration ;
    ax:businessImpact "Critical" ;
    ax:salaryPremium "33.0"^^xsd:decimal ;
    ax:appliesTo ax:MLEngineer, ax:DataEngineer, ax:AIEthicsOfficer .

ax:FinanceIndustryKnowledge a ax:DomainKnowledge ;
    rdfs:label "금융 산업 지식"@ko, "Finance Industry Knowledge"@en ;
    dcterms:description "여신 심사, 사기 탐지, 알고리즘 트레이딩"@ko ;
    ax:industryRelevance "Finance, Banking, Insurance" ;
    ax:marketDemand "78.3"^^xsd:decimal ;
    ax:emergingTrend false ;
    ax:learningTime "P6M"^^xsd:duration ;
    ax:businessImpact "High" ;
    ax:salaryPremium "28.0"^^xsd:decimal ;
    ax:appliesTo ax:DataScientist, ax:AIStrategist .

ax:HealthcareIndustryKnowledge a ax:DomainKnowledge ;
    rdfs:label "헬스케어 산업 지식"@ko, "Healthcare Industry Knowledge"@en ;
    dcterms:description "의료 영상 분석, 진단 지원, 신약 개발"@ko ;
