ax:RetailIndustryKnowledge a ax:DomainKnowledge ;
    rdfs:label "리테일 산업 지식"@ko, "Retail Industry Knowledge"@en ;
    dcterms:description "수요 예측, 추천 시스템, 가격 최적화"@ko ;
    ax:industryRelevance "Retail, E-commerce" ;
    ax:marketDemand "76.9"^^xsd:decimal ;
    ax:emergingTrend false ;
    ax:learningTime "P4M"^^xsd:duration ;
    ax:businessImpact "High" ;
    ax:salaryPremium "22.0"^^xsd:decimal ;
    ax:appliesTo ax:DataScientist, ax:AIProductManager .

ax:ManufacturingIndustryKnowledge a ax:DomainKnowledge ;
    rdfs:label "제조 산업 지식"@ko, "Manufacturing Industry Knowledge"@en ;
    dcterms:description "예지 정비, 품질 관리, 공정 최적화"@ko ;
    ax:industryRelevance "Manufacturing, Industrial IoT" ;
    ax:marketDemand "74.2"^^xsd:decimal ;
    ax:emergingTrend true ;
    ax:learningTime "P6M"^^xsd:duration ;
    ax:businessImpact "High" ;
    ax:salaryPremium "26.0"^^xsd:decimal ;
    ax:appliesTo ax:DataScientist, ax:MLEngineer .

# ========================================
# 역량 간 관계 정의
# ========================================

# 선행 조건 관계
ax:DeepLearning ax:requiresPrerequisite ax:MachineLearningFundamentals, ax:LinearAlgebra, ax:Python .
ax:NaturalLanguageProcessing ax:requiresPrerequisite ax:DeepLearning, ax:StatisticsAndProbability .
ax:LargeLanguageModels ax:requiresPrerequisite ax:NaturalLanguageProcessing, ax:PyTorch .
ax:RAGSystems ax:requiresPrerequisite ax:LargeLanguageModels, ax:Python, ax:Pinecone .
ax:ModelDeployment ax:requiresPrerequisite ax:Docker, ax:Python .
ax:MLOps ax:requiresPrerequisite ax:ModelDeployment, ax:Kubernetes, ax:GitHubActions .

# 시너지 관계
ax:PromptEngineering ax:synergizesWith ax:LargeLanguageModels, ax:CreativitySkill, ax:CriticalThinking .
ax:RAGSystems ax:synergizesWith ax:PromptEngineering, ax:VectorDatabases, ax:DataEngineering .
ax:MLOps ax:synergizesWith ax:DataOps, ax:CloudPlatforms, ax:CICD .
ax:AIEthics ax:synergizesWith ax:ExplainableAI, ax:FairnessBiasMitigation, ax:AIRegulation .
ax:ChangeManagement ax:synergizesWith ax:CommunicationSkills, ax:ChangeLeadership, ax:StakeholderManagement .

# 관련성 관계
ax:TensorFlow ax:relatedTo ax:PyTorch, ax:Keras .
ax:AWS ax:relatedTo ax:Azure, ax:GCP .
ax:Pinecone ax:relatedTo ax:Weaviate, ax:Chroma, ax:Milvus .
ax:LangChain ax:relatedTo ax:LlamaIndex .
ax:MLflow ax:relatedTo ax:Kubeflow .

# 대체 관계
ax:R ax:supersededBy ax:Python .
ax:Hadoop ax:supersededBy ax:Spark .

# 직무 적용 관계 (추가)
ax:MachineLearningFundamentals ax:appliesTo ax:MLEngineer, ax:DataScientist, ax:AIStrategist, ax:AIProductManager .
ax:LargeLanguageModels ax:appliesTo ax:MLEngineer, ax:PromptEngineer, ax:AIStrategist, ax:AIProductManager .
ax:DataPipeline ax:appliesTo ax:DataEngineer, ax:MLOpsEngineer, ax:MLEngineer .
ax:AIStrategyDevelopment ax:appliesTo ax:AIStrategist, ax:ChangeManagementLead .
ax:MLOps ax:appliesTo ax:MLOpsEngineer, ax:MLEngineer, ax:AIArchitect .

# ========================================
# 변혁 영역 (Transformation Areas)
# ========================================

ax:TransformationArea a owl:Class ;
    rdfs:label "변혁 영역"@ko .

ax:CustomerExperience a ax:TransformationArea ;
    rdfs:label "고객 경험"@ko .

ax:OperationalEfficiency a ax:TransformationArea ;
    rdfs:label "운영 효율성"@ko .

ax:ProductInnovation a ax:TransformationArea ;
    rdfs:label "제품 혁신"@ko .

ax:DecisionMaking a ax:TransformationArea ;
    rdfs:label "의사결정"@ko .

ax:WorkforceProductivity a ax:TransformationArea ;
    rdfs:label "인력 생산성"@ko .

# 변혁 가능 영역 관계
ax:LargeLanguageModels ax:enablesTransformation ax:CustomerExperience, ax:WorkforceProductivity .
ax:ComputerVision ax:enablesTransformation ax:OperationalEfficiency, ax:ProductInnovation .
ax:PromptEngineering ax:enablesTransformation ax:WorkforceProductivity, ax:CustomerExperience .
ax:MLOps ax:enablesTransformation ax:OperationalEfficiency .
ax:AIStrategyDevelopment ax:enablesTransformation ax:DecisionMaking, ax:ProductInnovation .

