{"language": "plaintext", "code": "@prefix ax: <http://example.org/ai-transformation#> .
@prefix rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#> .
@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .
@prefix owl: <http://www.w3.org/2002/07/owl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .
@prefix skos: <http://www.w3.org/2004/02/skos/core#> .
@prefix dcterms: <http://purl.org/dc/terms/> .

# ========================================
# 온톨로지 메타데이터
# ========================================
<http://example.org/ai-transformation> a owl:Ontology ;
    dcterms:title "AI Transformation Competency Ontology"@en ;
    dcterms:title "AI 전환 역량 온톨로지"@ko ;
    dcterms:description "Comprehensive ontology for AI Transformation competencies and skills"@en ;
    dcterms:creator "AI Transformation Competency Framework Team" ;
    dcterms:created "2024-12-09"^^xsd:date ;
    owl:versionInfo "1.0.0" ;
    dcterms:license "Apache License 2.0" .

# ========================================
# 핵심 클래스 정의
# ========================================
ax:Competency a owl:Class ;
    rdfs:label "역량"@ko, "Competency"@en ;
    rdfs:comment "AI 전환 관련 모든 역량의 최상위 클래스"@ko .

ax:TechnicalSkill a owl:Class ;
    rdfs:subClassOf ax:Competency ;
    rdfs:label "기술 스킬"@ko, "Technical Skill"@en ;
    rdfs:comment "AI/ML 기술적 역량"@ko .

ax:SoftSkill a owl:Class ;
    rdfs:subClassOf ax:Competency ;
    rdfs:label "소프트 스킬"@ko, "Soft Skill"@en ;
    rdfs:comment "대인관계 및 조직 역량"@ko .

ax:Tool a owl:Class ;
    rdfs:subClassOf ax:Competency ;
    rdfs:label "도구"@ko, "Tool"@en ;
    rdfs:comment "AI 개발 및 운영 도구"@ko .

ax:Methodology a owl:Class ;
    rdfs:subClassOf ax:Competency ;
    rdfs:label "방법론"@ko, "Methodology"@en ;
    rdfs:comment "AI 프로젝트 및 조직 변혁 방법론"@ko .

ax:DomainKnowledge a owl:Class ;
    rdfs:subClassOf ax:Competency ;
    rdfs:label "도메인 지식"@ko, "Domain Knowledge"@en ;
    rdfs:comment "특정 산업/분야 AI 적용 지식"@ko .

ax:JobRole a owl:Class ;
    rdfs:label "직무 역할"@ko, "Job Role"@en .

ax:CompetencyCluster a owl:Class ;
    rdfs:label "역량 클러스터"@ko, "Competency Cluster"@en ;
    rdfs:comment "관련 역량들의 그룹"@ko .

# ========================================
# 속성 정의
# ========================================

# 데이터 속성
ax:proficiencyLevel a owl:DatatypeProperty ;
    rdfs:domain ax:Competency ;
    rdfs:range xsd:integer ;
    rdfs:label "숙련도 수준"@ko ;
    rdfs:comment "1:초급, 2:중급, 3:고급, 4:전문가, 5:마스터"@ko .

ax:marketDemand a owl:DatatypeProperty ;
    rdfs:domain ax:Competency ;
    rdfs:range xsd:decimal ;
    rdfs:label "시장 수요"@ko ;
    rdfs:comment "0-100 범위의 시장 수요 지수"@ko .

ax:emergingTrend a owl:DatatypeProperty ;
    rdfs:domain ax:Competency ;
    rdfs:range xsd:boolean ;
    rdfs:label "신규 트렌드"@ko .

ax:halfLife a owl:DatatypeProperty ;
    rdfs:domain ax:Competency ;
    rdfs:range xsd:duration ;
    rdfs:label "스킬 반감기"@ko .

ax:learningTime a owl:DatatypeProperty ;
    rdfs:domain ax:Competency ;
    rdfs:range xsd:duration ;
    rdfs:label "학습 소요 시간"@ko .

ax:businessImpact a owl:DatatypeProperty ;
    rdfs:domain ax:Competency ;
    rdfs:range xsd:string ;
    rdfs:label "비즈니스 영향도"@ko ;
    rdfs:comment "Low, Medium, High, Critical"@en .

ax:aiMaturityLevel a owl:DatatypeProperty ;
    rdfs:domain ax:Competency ;
    rdfs:range xsd:integer ;
    rdfs:label "AI 성숙도 레벨"@ko ;
    rdfs:comment "1:인식, 2:실험, 3:파일럿, 4:운영, 5:최적화"@ko .

ax:industryRelevance a owl:DatatypeProperty ;
    rdfs:domain ax:Competency ;
    rdfs:range xsd:string ;
    rdfs:label "산업 관련성"@ko .

ax:certificationAvailable a owl:DatatypeProperty ;
    rdfs:domain ax:Competency ;
    rdfs:range xsd:boolean ;
    rdfs:label "자격증 가능 여부"@ko .

ax:salary premium a owl:DatatypeProperty ;
    rdfs:domain ax:Competency ;
    rdfs:range xsd:decimal ;
    rdfs:label "연봉 프리미엄"@ko ;
    rdfs:comment "해당 스킬 보유 시 평균 연봉 증가율 (%)"@ko .

# 객체 속성
ax:requiresPrerequisite a owl:ObjectProperty ;
    rdfs:domain ax:Competency ;
    rdfs:range ax:Competency ;
    rdfs:label "선행 조건"@ko .

ax:relatedTo a owl:ObjectProperty, owl:SymmetricProperty ;
    rdfs:domain ax:Competency ;
    rdfs:range ax:Competency ;
    rdfs:label "관련됨"@ko .

ax:supersededBy a owl:ObjectProperty ;
    rdfs:domain ax:Competency ;
    rdfs:range ax:Competency ;
    rdfs:label "대체됨"@ko .

ax:appliesTo a owl:ObjectProperty ;
    rdfs:domain ax:Competency ;
    rdfs:range ax:JobRole ;
    rdfs:label "적용 직무"@ko .

ax:enablesTransformation a owl:ObjectProperty ;
    rdfs:domain ax:Competency ;
    rdfs:range ax:TransformationArea ;
    rdfs:label "변혁 가능 영역"@ko .

ax:synergizesWith a owl:ObjectProperty, owl:SymmetricProperty ;
    rdfs:domain ax:Competency ;
    rdfs:range ax:Competency ;
    rdfs:label "시너지 효과"@ko .

ax:partOfCluster a owl:ObjectProperty ;
    rdfs:domain ax:Competency ;
    rdfs:range ax:CompetencyCluster ;
    rdfs:label "클러스터 소속"@ko .

# ========================================
# 역량 클러스터 정의
# ========================================

ax:AIFoundationsCluster a ax:CompetencyCluster ;
    rdfs:label "AI 기초 역량군"@ko, "AI Foundations Cluster"@en ;
    dcterms:description "AI/ML의 기본 개념과 수학적 기초"@ko .

ax:MLEngineeringCluster a ax:CompetencyCluster ;
    rdfs:label "ML 엔지니어링 역량군"@ko, "ML Engineering Cluster"@en ;
    dcterms:description "머신러닝 모델 개발 및 배포"@ko .

ax:DataEngineeringCluster a ax:CompetencyCluster ;
    rdfs:label "데이터 엔지니어링 역량군"@ko, "Data Engineering Cluster"@en ;
    dcterms:description "데이터 파이프라인 및 인프라"@ko .

ax:AIStrategyCluster a ax:CompetencyCluster ;
    rdfs:label "AI 전략 역량군"@ko, "AI Strategy Cluster"@en ;
    dcterms:description "AI 전략 수립 및 실행"@ko .

ax:AIGovernanceCluster a ax:CompetencyCluster ;
    rdfs:label "AI 거버넌스 역량군"@ko, "AI Governance Cluster"@en ;
    dcterms:description "AI 윤리, 규제, 리스크 관리"@ko .

ax:BusinessTransformationCluster a ax:CompetencyCluster ;
    rdfs:label "비즈니스 변혁 역량군"@ko, "Business Transformation Cluster"@en ;
    dcterms:description "조직 변화 관리 및 프로세스 혁신"@ko .

ax:GenerativeAICluster a ax:CompetencyCluster ;
    rdfs:label "생성형 AI 역량군"@ko, "Generative AI Cluster"@en ;
    dcterms:description "LLM 및 생성형 AI 활용"@ko .

# ========================================
# 직무 역할 정의
# ========================================

ax:AIStrategist a ax:JobRole ;
    rdfs:label "AI 전략가"@ko, "AI Strategist"@en ;
    dcterms:description "조직의 AI 전략 수립 및 실행을 주도"@ko ;
    ax:seniorityLevel "Senior"@en ;
    ax:typicalExperience "10+"^^xsd:integer .

ax:MLEngineer a ax:JobRole ;
    rdfs:label "ML 엔지니어"@ko, "ML Engineer"@en ;
    dcterms:description "머신러닝 모델 설계, 개발, 배포"@ko ;
    ax:seniorityLevel "Mid to Senior"@en ;
    ax:typicalExperience "3-7"^^xsd:integer .

ax:DataScientist a ax:JobRole ;
    rdfs:label "데이터 사이언티스트"@ko, "Data Scientist"@en ;
    dcterms:description "데이터 분석 및 인사이트 도출"@ko ;
    ax:seniorityLevel "Mid to Senior"@en ;
    ax:typicalExperience "3-7"^^xsd:integer .

ax:AIProductManager a ax:JobRole ;
    rdfs:label "AI 프로덕트 매니저"@ko, "AI Product Manager"@en ;
    dcterms:description "AI 제품 기획 및 관리"@ko ;
    ax:seniorityLevel "Mid to Senior"@en ;
    ax:typicalExperience "5-10"^^xsd:integer .

ax:MLOpsEngineer a ax:JobRole ;
    rdfs:label "MLOps 엔지니어"@ko, "MLOps Engineer"@en ;
    dcterms:description "ML 시스템 운영 및 자동화"@ko ;
    ax:seniorityLevel "Mid"@en ;
    ax:typicalExperience "3-5"^^xsd:integer .

ax:DataEngineer a ax:JobRole ;
    rdfs:label "데이터 엔지니어"@ko, "Data Engineer"@en ;
    dcterms:description "데이터 파이프라인 구축 및 관리"@ko ;
    ax:seniorityLevel "Mid"@en ;
    ax:typicalExperience "3-5"^^xsd:integer .

ax:AIEthicsOfficer a ax:JobRole ;
    rdfs:label "AI 윤리 책임자"@ko, "AI Ethics Officer"@en ;
    dcterms:description "AI 윤리 기준 수립 및 준수 관리"@ko ;
    ax:seniorityLevel "Senior"@en ;
    ax:typicalExperience "8+"^^xsd:integer .

ax:ChangeManagementLead a ax:JobRole ;
    rdfs:label "변화관리 리드"@ko, "Change Management Lead"@en ;
    dcterms:description "AI 도입 조직 변화 관리"@ko ;
    ax:seniorityLevel "Senior"@en ;
    ax:typicalExperience "7+"^^xsd:integer .

ax:PromptEngineer a ax:JobRole ;
    rdfs:label "프롬프트 엔지니어"@ko, "Prompt Engineer"@en ;
    dcterms:description "LLM 프롬프트 설계 및 최적화"@ko ;
    ax:seniorityLevel "Mid"@en ;
    ax:typicalExperience "2-4"^^xsd:integer .

ax:AIArchitect a ax:JobRole ;
    rdfs:label "AI 아키텍트"@ko, "AI Architect"@en ;
    dcterms:description "AI 시스템 아키텍처 설계"@ko ;
    ax:seniorityLevel "Senior"@en ;
    ax:typicalExperience "10+"^^xsd:integer .

# ========================================
# 기술 스킬 - AI/ML 기초
# ========================================

ax:MachineLearningFundamentals a ax:TechnicalSkill ;
    rdfs:label "머신러닝 기초"@ko, "Machine Learning Fundamentals"@en ;
    dcterms:description "지도학습, 비지도학습, 강화학습 기본 개념"@ko ;
    ax:partOfCluster ax:AIFoundationsCluster ;
    ax:marketDemand "95.5"^^xsd:decimal ;
    ax:emergingTrend false ;
    ax:learningTime "P3M"^^xsd:duration ;
    ax:businessImpact "Critical" ;
